#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long x1,x2,y1,y2; // use long long for safety
        scanf("%lld %lld %lld %lld", &x1, &x2, &y1, &y2);
        long long left = y1 * x2;
        long long right = y2 * x1;
        if(left < right) printf("-1\n");
        else if(left > right) printf("1\n");
        else printf("0\n");
    }
    return 0;
}

