import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        x1 = int(next(it)); x2 = int(next(it)); y1 = int(next(it)); y2 = int(next(it))
        left = y1 * x2
        right = y2 * x1
        if left < right:
            out.append('-1')
        elif left > right:
            out.append('1')
        else:
            out.append('0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

